function has_close_elements(numbers, threshold) {
    if (numbers.length < 2) return false;

    const sorted = [...numbers].sort((a, b) => a - b);

    for (let i = 0; i < sorted.length - 1; i++) {
        if (sorted[i + 1] - sorted[i] < threshold) {
            return true;
        }
    }

    return false;
}

function separate_paren_groups(paren_string) {
    const result = [];
    let currentGroup = '';
    let balance = 0;

    for (let i = 0; i < paren_string.length; i++) {
        const char = paren_string[i];

        if (char === ' ') continue;

        if (char === '(') {
            currentGroup += char;
            balance++;
        } else if (char === ')') {
            currentGroup += char;
            balance--;

            if (balance === 0) {
                result.push(currentGroup);
                currentGroup = '';
            }
        }
    }

    return result;
}

